void computeZArray(vector<ll> &z_arr,
                   const string &txt,
                   const string &pat)
{
    // Build concatenated string: pattern + '$' + text
    string s = pat + '$' + txt;
    ll n = s.size();

    // Allocate and zero‑initialize
    z_arr.assign(n, 0);

    ll l = 0, r = 0;
    for (ll i = 1; i < n; i++)
    {
        if (i <= r)
            z_arr[i] = min(r - i + 1, z_arr[i - l]);

        // Try to extend match at i
        while (i + z_arr[i] < n && s[z_arr[i]] == s[i + z_arr[i]])
            z_arr[i]++;

        // Update [l, r] if we've extended beyond r
        if (i + z_arr[i] - 1 > r)
        {
            l = i;
            r = i + z_arr[i] - 1;
        }
    }
}

vector<ll> zFunction(const string &txt,
                     const string &pat)
{
    // O(n + m)
    // O(n + m) + n(for ans array in computeZArr)

    ll n = txt.size();
    ll m = pat.size();

    // Compute Z array on pat + '$' + txt
    vector<ll> z_arr;
    computeZArray(z_arr, txt, pat);

    // Collect match positions
    vector<ll> ans;
    // Z-values for positions i = m+1 .. m+1 + n - 1
    for (ll i = m + 1; i < m + 1 + n; i++)
    {
        if (z_arr[i] == m)
            ans.push_back(i - (m + 1));
    }

    return ans;
}
class DisjointSet
{
    // TC ->  O(V)(for initializing using constructor)
    // SC -> O(V) (for storing rank and parent)
public:
    vector<ll> rank, parent, size;
    DisjointSet(ll n)
    {
        rank.resize(n + 1, 0);
        parent.resize(n + 1);
        size.resize(n + 1, 1);
        for (ll i = 0; i <= n; i++)
        {
            parent[i] = i;
        }
    }
    ll findUPar(ll node)
    {
        // TC -> O(4*alpha) ~= O(1)
        // SC -> O(1)
        if (node == parent[node])
            return node;
        return parent[node] = findUPar(parent[node]);
    }
    void unionByRank(ll u, ll v)
    {
        // TC -> O(4*alpha) ~= O(1)
        // SC -> O(1)
        ll ulp_u = findUPar(u);
        ll ulp_v = findUPar(v);
        if (ulp_u == ulp_v)
            return;
        if (rank[ulp_u] < rank[ulp_v])
        {
            parent[ulp_u] = ulp_v;
        }
        else if (rank[ulp_v] < rank[ulp_u])
        {
            parent[ulp_v] = ulp_u;
        }
        else
        {
            parent[ulp_v] = ulp_u;
            rank[ulp_u]++;
        }
    }
    void unionBySize(ll u, ll v)
    {
        // TC -> O(4*alpha) ~= O(1)
        // SC -> O(1)
        ll ulp_u = findUPar(u);
        ll ulp_v = findUPar(v);
        if (ulp_u == ulp_v)
            return;
        if (rank[ulp_u] <= rank[ulp_v])
        {
            parent[ulp_u] = ulp_v;
            size[ulp_v] += size[ulp_u];
        }
        else
        {
            parent[ulp_v] = ulp_u;
            size[ulp_u] += size[ulp_v];
        }
    }
    ll numOfConnectedComponentsZeroIndex()
    {
        // TC -> O(n)
        // SC -> O(1)
        ll n = parent.size();
        ll cnt = 0;
        for (ll i = 0; i < n - 1; i++)
        {
            if (parent[i] == i)
                cnt++;
        }
        return cnt;
    }
    ll numOfConnectedComponentsOneIndex()
    {
        // TC -> O(n)
        // SC -> O(1)
        ll n = parent.size();
        ll cnt = 0;
        for (ll i = 1; i < n; i++)
        {
            if (parent[i] == i)
                cnt++;
        }
        return cnt;
    }
};
