    string s = pat + '$' + txt;
    ll n = s.size();

    // Allocate and zero‑initialize
    z_arr.assign(n, 0);

    ll l = 0, r = 0;
    for (ll i = 1; i < n; i++)
    {
        if (i <= r)
            z_arr[i] = min(r - i + 1, z_arr[i - l]);

        // Try to extend match at i
        while (i + z_arr[i] < n && s[z_arr[i]] == s[i + z_arr[i]])
            z_arr[i]++;

        // Update [l, r] if we've extended beyond r
        if (i + z_arr[i] - 1 > r)
        {
            l = i;
            r = i + z_arr[i] - 1;
        }
    }
}

